---@type lproject
local lproject = require("lproject")

----@type ltw2_core
local lcore = require("ltw2.core")

----@type ltw2_event
local levent = require("ltw2.event")

local LuaHelper = require("Utility.luaHelper")

local tickerList = {}

local timerList = {}

local function Tick(deltaTime)
	levent.run()
	for obj, func in pairs(tickerList) do
		LuaHelper.XpCall(func, obj, deltaTime * 1000)
	end
end

local function ReceiveBeginPlay()
	assert(levent.start(1), "levent.start failed")
end

local function ReceiveEndPlay()
	-- 安全地停止所有 timer
	for timer in pairs(timerList) do
		-- 使用 pcall 保护调用，避免访问已释放的对象导致崩溃
		pcall(function()
			if timer then
				timer:stop()
			end
		end)
    end
	timerList = {}
	
	-- 安全地停止事件循环
	pcall(function()
		levent.stop()
	end)
end

