--
--lproject.set_endplay_callback(ReceiveEndPlay)

---@class EventLoop
local M = {}

---@return boolean
function M.Startup()
	return lproject.startup()
end

---@return boolean
function M.Shutdown()
	return lproject.shutdown()
end
---@param obj any
---@param func function
function M.AddTicker(obj, func)
	tickerList[obj] = func
end

---@param obj any
function M.DelTicker(obj)
	tickerList[obj] = nil
end

function M.ResetTicker()
	tickerList = {}
end

---@return integer
function M.ClockMonotonic()
	return lcore.clock_monotonic()
end

---@return integer
function M.ClockRealtime()
	return lcore.clock_realtime()
end

---@param duration integer
function M.SleepFor(duration)
	lcore.sleep_for(duration)
end

---@param intervalMs integer
---@param func function
---@return ltw2_event_timer_watcher
function M.Timeout(intervalMs, func, bLoop)
	local timer = levent.timer_watcher_new()
	-- 检查 timer 是否创建成功
	if not timer then
		return nil
	end
	
	if not timer:start(intervalMs, not bLoop, function()
		func()
		if not bLoop then
			timerList[timer] = nil
		end
	end) then
        return nil
    end
	timerList[timer] = timer
	return timer
end

return M